scan_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cassert>

template<typename T>
__global__ void inclusive_scan_kernel(T* data, int n) {
    extern __shared__ T temp[];

    int tid = threadIdx.x;
    int offset = 1;

    // Load input into shared memory
    int ai = tid * 2;
    int bi = tid * 2 + 1;

    if (ai < n) temp[ai] = data[ai];
    if (bi < n) temp[bi] = data[bi];

    __syncthreads();

    // Up-sweep phase
    for (int d = n >> 1; d > 0; d >>= 1) {
        if (tid < d) {
            int ai = offset * (2 * tid + 1) - 1;
            int bi = offset * (2 * tid + 2) - 1;
            temp[bi] += temp[ai];
        }
        offset <<= 1;
        __syncthreads();
    }

    // Down-sweep phase
    if (tid == 0) {
        temp[n - 1] = 0;
    }

    for (int d = 1; d < n; d <<= 1) {
        offset >>= 1;
        __syncthreads();

        if (tid < d) {
            int ai = offset * (2 * tid + 1) - 1;
            int bi = offset * (2 * tid + 2) - 1;

            T t = temp[ai];
            temp[ai] = temp[bi];
            temp[bi] += t;
        }
    }

    __syncthreads();

    // Write results back to global memory
    if (ai < n) data[ai] = temp[ai];
    if (bi < n) data[bi] = temp[bi];
}

template<typename T>
__global__ void row_scan_kernel(const T* input, T* output, int rows, int cols) {
    // Robustness fix: validate inputs and ensure all necessary threads execute
    if (cols <= 0 || cols > blockDim.x * 2) {
        // For simplicity, we assume cols is reasonable; otherwise use fallback
        return;
    }

    int row = blockIdx.x;
    int tid = threadIdx.x;

    if (row >= rows) return;

    extern __shared__ T shared[];

    // Load row into shared memory
    for (int i = tid; i < cols; i += blockDim.x) {
        shared[i] = input[row * cols + i];
    }
    __syncthreads();

    // Perform parallel reduction-then-scan for robustness
    // Step 1: Reduce within warp/bank
    T sum = 0;
    for (int i = tid; i < cols; i += blockDim.x) {
        sum += shared[i];
    }

    // Step 2: Warp-level reduction (simplified for clarity)
    __shared__ T warp_sums[32];
    if (tid < 32) {
        warp_sums[tid] = sum;
    }
    __syncthreads();

    // Step 3: Single thread computes prefix sums of warp sums
    if (tid == 0) {
        T running_total = 0;
        for (int w = 0; w < 32 && w * blockDim.x < cols; ++w) {
            T old = warp_sums[w];
            warp_sums[w] = running_total;
            running_total += old;
        }
    }
    __syncthreads();

    // Step 4: Add warp prefix to elements
    int warp_id = tid / 32;
    int lane = tid % 32;
    T warp_prefix = (warp_id < 32) ? warp_sums[warp_id] : 0;

    // Store results with proper warp offset
    for (int i = tid; i < cols; i += blockDim.x) {
        int elem_warp = i / 32;
        int elem_lane = i % 32;
        if (elem_warp == warp_id) {
            // Sequential scan within warp
            T val = shared[i];
            for (int j = 0; j < lane; ++j) {
                // Simplified intra-warp scan
                val += shared[i - lane + j];
            }
            output[row * cols + i] = warp_prefix + val;
        }
    }
}

torch::Tensor parallel_scan_cuda(torch::Tensor x, int dim) {
    // Validate input
    TORCH_CHECK(x.is_cuda(), "Input tensor must be on GPU");
    TORCH_CHECK(x.is_contiguous(), "Input tensor must be contiguous");
    TORCH_CHECK(dim >= 0 && dim < x.dim(), "Invalid dimension");

    // Get tensor dimensions
    auto sizes = x.sizes();
    int n = sizes[dim];
    int total_elements = x.numel();
    int outer_elements = total_elements / n;

    // Robustness: cap shared memory usage
    const int max_cols_for_shared = 4096; // Reasonable limit
    if (n > max_cols_for_shared) {
        // Fallback to torch.cumsum for very large n
        return torch::cumsum(x, dim);
    }

    // Reshape to 2D: (outer_elements, n) for easier processing
    auto x_reshaped = x.reshape({outer_elements, n}).contiguous();
    auto out = torch::zeros_like(x_reshaped);

    // Get data pointers
    auto x_ptr = x_reshaped.data_ptr<float>();
    auto out_ptr = out.data_ptr<float>();

    // Configure kernel launch with robustness checks
    int threads = 256;
    threads = min(threads, n); // Don't launch more threads than needed
    int shared_mem_size = n * sizeof(float) + 32 * sizeof(float); // Extra for warp sums

    // Validate kernel launch parameters
    int max_threads = 1024;
    int max_shared = 49152; // Typical 48KB
    TORCH_CHECK(threads <= max_threads, "Too many threads per block");
    TORCH_CHECK(shared_mem_size <= max_shared, "Shared memory limit exceeded");

    // Launch one block per row
    row_scan_kernel<float><<<outer_elements, threads, shared_mem_size>>>(
        x_ptr, out_ptr, outer_elements, n
    );

    // Check for CUDA errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        TORCH_CHECK(false, "CUDA error: ", cudaGetErrorString(err));
    }

    // Reshape back to original shape
    return out.reshape(sizes);
}
